import React from "react";
import { ArrowLeft } from "lucide-react";

export default function AddMoneyOptionsScreen({ onBack, onSelectOption }) {
  const options = [
    { id: 1, title: "Bank Transfer" },
    { id: 2, title: "Debit/Credit Card" },
    { id: 3, title: "USSD" },
  ];

  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24">
      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft className="w-6 h-6 text-gray-700" />
        </button>
        <h1 className="text-xl font-semibold text-gray-900">
          Add Money
        </h1>
      </div>

      {/* Options */}
      <div className="space-y-4">
        {options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => onSelectOption(opt)}
            className="w-full bg-white rounded-xl p-4 shadow-sm text-left active:scale-[0.98] transition"
          >
            {opt.title}
          </button>
        ))}
      </div>
    </div>
  );
}
